  @staticmethod
  def _map_jira_service_management_priority(severity: str) -> str:
    normalized = severity.lower()
    if normalized in {"critical", "error"}:
      return "highest"
    if normalized in {"warning", "warn"}:
      return "high"
    return "medium"

